// Data arrives via Merge node with 4 inputs
// Input 0 = Fetch Daily Stats, Input 1 = Fetch Balance,
// Input 2 = Fetch Geo Stats, Input 3 = Fetch CRM Leads
const statsRaw = $input.all()[0]?.json || {};
const balanceRaw = $input.all()[1]?.json || {};
const geoRaw = $input.all()[2]?.json || {};
const crmItems = $input.all().slice(3).map(i => i.json);

const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);
const balance = Number(balanceRaw?.data?.balance || balanceRaw?.balance || 0);
const geoStats = geoRaw?.data?.result?.data || geoRaw?.data || (Array.isArray(geoRaw) ? geoRaw : []);

// CRM map: ad_id -> { leads, deps, revenue }
const crmMap = {};
let totalLeads = 0, totalDeps = 0, totalCrmRevenue = 0;
crmItems.forEach(c => {
  const adId = Number(c.ad_id);
  if (adId) {
    const leads = Number(c.total_leads) || 0;
    const deps = Number(c.depositors) || 0;
    const rev = Number(c.crm_revenue) || 0;
    crmMap[adId] = { leads, deps, revenue: rev };
    totalLeads += leads;
    totalDeps += deps;
    totalCrmRevenue += rev;
  }
});

let totalSpend = 0, totalClicks = 0, totalShows = 0;
const adPerformance = [];

if (Array.isArray(stats)) {
  stats.forEach(s => {
    const spend = Number(s.money) || 0;
    const clicks = Number(s.clicks_count) || 0;
    const shows = Number(s.shows_count) || 0;
    const adId = s.ad_id;
    const crm = crmMap[adId] || { leads: 0, deps: 0, revenue: 0 };
    const revenue = crm.revenue;
    const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;
    const cpl = crm.leads > 0 ? spend / crm.leads : (spend > 0 ? Infinity : 0);

    totalSpend += spend;
    totalClicks += clicks;
    totalShows += shows;

    adPerformance.push({ ad_id: adId, spend, revenue, roi, clicks, leads: crm.leads, deps: crm.deps, cpl });
  });
}

adPerformance.sort((a, b) => b.roi - a.roi);

const totalRoi = totalSpend > 0 ? ((totalCrmRevenue - totalSpend) / totalSpend * 100) : 0;
const totalProfit = totalCrmRevenue - totalSpend;
const totalCpl = totalLeads > 0 ? totalSpend / totalLeads : 0;
const top5 = adPerformance.filter(a => a.roi > 0).slice(0, 5);
const worst5 = adPerformance.filter(a => a.spend > 5 && a.leads === 0).sort((a, b) => b.spend - a.spend).slice(0, 5);
const activeAds = adPerformance.filter(a => a.clicks > 0).length;

const geoBreakdown = [];
if (Array.isArray(geoStats)) {
  geoStats.forEach(g => {
    const spend = Number(g.money) || 0;
    geoBreakdown.push({ country: g.country_code, spend });
  });
  geoBreakdown.sort((a, b) => b.spend - a.spend);
}

// Build report text
const date = $now.toFormat('dd.MM.yyyy');
const profitSign = totalProfit >= 0 ? '+' : '';

let msg = `DAILY REPORT ${date}\n`;
msg += `\nBalance: $${balance.toFixed(2)}`;
msg += `\nSpend: $${totalSpend.toFixed(2)} | Revenue (CRM): $${totalCrmRevenue.toFixed(2)}`;
msg += `\nProfit: ${profitSign}$${totalProfit.toFixed(2)} | ROI: ${totalRoi.toFixed(1)}%`;
msg += `\nLeads: ${totalLeads} | Deps: ${totalDeps} | CPL: $${totalCpl.toFixed(2)}`;
msg += `\nClicks: ${totalClicks} | Shows: ${totalShows} | Ads: ${activeAds}`;

if (top5.length > 0) {
  msg += `\n\nTOP ${top5.length} (by ROI):`;
  top5.forEach(a => {
    msg += `\n  #${a.ad_id}: ROI ${a.roi.toFixed(0)}% profit $${(a.revenue - a.spend).toFixed(2)} (${a.leads}L/${a.deps}D)`;
  });
}

if (worst5.length > 0) {
  msg += `\n\nDRAIN (spend, 0 leads):`;
  worst5.forEach(a => {
    msg += `\n  #${a.ad_id}: spent $${a.spend.toFixed(2)} ${a.clicks}cl 0 leads`;
  });
}

if (geoBreakdown.length > 0) {
  msg += `\n\nGEO spend:`;
  geoBreakdown.slice(0, 10).forEach(g => {
    msg += `\n  ${g.country}: $${g.spend.toFixed(2)}`;
  });
}

return [{
  json: {
    date: $now.toFormat('yyyy-MM-dd'),
    balance: Math.round(balance * 100) / 100,
    total_spend: Math.round(totalSpend * 100) / 100,
    total_revenue: Math.round(totalCrmRevenue * 100) / 100,
    total_profit: Math.round(totalProfit * 100) / 100,
    total_roi: Math.round(totalRoi * 100) / 100,
    report_text: msg
  }
}];
